DE="unknown"
detect_de() {
  local d="${XDG_CURRENT_DESKTOP:-${DESKTOP_SESSION:-}}"
  d="$(printf '%s' "$d" | tr '[:upper:]' '[:lower:]')"
  case "$d" in
    *gnome*|*ubuntu*|*unity*) DE="gnome" ;;
    *cinnamon*)               DE="cinnamon" ;;
    *kde*|*plasma*)           DE="kde" ;;
    *xfce*)                   DE="xfce" ;;
    *mate*)                   DE="mate" ;;
    *)                        DE="unknown" ;;
  esac
}

# Run a command as the logged-in desktop user (settings are per-user).
run_as_user() {
  local uid; uid="$(id -u "$TARGET_USER" 2>/dev/null)"
  sudo -u "$TARGET_USER" \
    DBUS_SESSION_BUS_ADDRESS="unix:path=/run/user/${uid}/bus" \
    DISPLAY="${DISPLAY:-:0}" "$@"
}

# Record a successfully-applied setting so it appears in the end-of-run summary.
# (The bare ok()/info()/log() helpers only print to the screen; they do NOT record,
# which is why applied settings were previously missing from the summary.)
mark_set() { OK_LIST+=("$1"); record_line OK "$1" "${2:-}"; ok "applied: $1"; }

gset() {  # gset SCHEMA KEY VALUE  (GNOME/Cinnamon share most schemas)
  # Idempotent + schema-aware:
  #   - if the schema/key does not exist on this DE -> skip quietly (no failure noise)
  #   - if the current value already equals VALUE   -> skip (don't re-run the change)
  #   - otherwise set it and record the change
  local cur
  if ! run_as_user gsettings list-keys "$1" 2>/dev/null | grep -qx "$2"; then
    mark_skip "$1 $2" "not available on $DE"; return 0
  fi
  cur="$(run_as_user gsettings get "$1" "$2" 2>/dev/null)"
  if [ -n "$cur" ] && [ "$cur" = "$3" ]; then
    mark_skip "$1 $2" "already set ($3)"; return 0
  fi
  if capture run_as_user gsettings set "$1" "$2" "$3"; then
    mark_set "$1 $2 = $3"
  else
    mark_fail "config: $1 $2" "${LAST_ERR:-could not set (schema may not exist on $DE)}"
  fi
}

apply_display_scaling() {
  [ -z "${CFG_scaling:-}" ] && return 0
  local pct factor; pct="$(printf '%s' "$CFG_scaling" | tr -cd '0-9')"
  [ -z "$pct" ] && return 0
  # LC_NUMERIC=C forces a '.' decimal separator; gsettings rejects locale commas (e.g. "1,50").
  factor="$(LC_NUMERIC=C awk "BEGIN{printf \"%.2f\", $pct/100}")"
  log "Display scaling: ${CFG_scaling} (text-scaling-factor ${factor})"
  case "$DE" in
    gnome|cinnamon) gset org.gnome.desktop.interface text-scaling-factor "$factor" ;;
    *) mark_manual "display scaling" "set scaling to ${CFG_scaling} in your DE settings" ;;
  esac
}

apply_lock_timeout() {
  [ -z "${CFG_lock_timeout:-}" ] && return 0
  local mins secs; mins="$(printf '%s' "$CFG_lock_timeout" | tr -cd '0-9')"
  log "Screen lock timeout: ${CFG_lock_timeout}"
  case "$(printf '%s' "$CFG_lock_timeout" | tr '[:upper:]' '[:lower:]')" in
    *never*) secs=0 ;;
    *) secs=$(( ${mins:-10} * 60 )) ;;
  esac
  case "$DE" in
    gnome|cinnamon)
      gset org.gnome.desktop.session idle-delay "uint32 ${secs}"
      if [ "$secs" -eq 0 ]; then gset org.gnome.desktop.screensaver lock-enabled false
      else gset org.gnome.desktop.screensaver lock-enabled true; fi
      # Disabling the idle autolock should NOT disable locking on suspend/resume.
      # (ubuntu-lock-on-suspend exists only on Ubuntu; gset skips it elsewhere.)
      gset org.gnome.desktop.screensaver lock-on-suspend true
      gset org.gnome.desktop.screensaver ubuntu-lock-on-suspend true ;;
    *) mark_manual "lock timeout" "set screen lock to ${CFG_lock_timeout} in your DE settings" ;;
  esac
}

apply_keyboard_layout() {
  # Skip the whole module only when nothing keyboard-related was captured.
  [ -z "${CFG_keyboard_layout:-}${CFG_key_repeat_delay:-}${CFG_key_repeat_rate:-}${CFG_numlock:-}" ] && return 0
  log "Keyboard settings"
  if [ -n "${CFG_keyboard_layout:-}" ]; then
    # Map free-text layout to xkb codes (best-effort).
    local layouts="us"
    printf '%s' "$CFG_keyboard_layout" | grep -qi 'fa\|persian' && layouts="us,ir"
    case "$DE" in
      gnome|cinnamon)
        local srcs="[('xkb', 'us')]"
        [ "$layouts" = "us,ir" ] && srcs="[('xkb', 'us'), ('xkb', 'ir')]"
        gset org.gnome.desktop.input-sources sources "$srcs" ;;
      *) if have_cmd localectl; then
           if capture localectl set-x11-keymap "$layouts"; then mark_set "x11 keymap = $layouts"
           else mark_fail "keyboard layout" "${LAST_ERR:-localectl set-x11-keymap failed}"; fi
         fi ;;
    esac
  fi
  # Key-repeat speed and NumLock state (GNOME/Cinnamon).
  case "$DE" in
    gnome|cinnamon)
      [ -n "${CFG_key_repeat_delay:-}" ] && gset org.gnome.desktop.peripherals.keyboard delay "uint32 ${CFG_key_repeat_delay}"
      [ -n "${CFG_key_repeat_rate:-}" ]  && gset org.gnome.desktop.peripherals.keyboard repeat-interval "uint32 ${CFG_key_repeat_rate}"
      if [ -n "${CFG_numlock:-}" ]; then
        gset org.gnome.desktop.peripherals.keyboard remember-numlock-state true
        gset org.gnome.desktop.peripherals.keyboard numlock-state "$CFG_numlock"
      fi ;;
  esac
}

disable_telemetry_location() {
  [ -z "${CFG_location:-}${CFG_telemetry:-}" ] && return 0
  log "Privacy & security"
  if systemctl is-enabled geoclue.service >/dev/null 2>&1; then
    if capture systemctl disable --now geoclue.service; then mark_set "telemetry/location: disabled geoclue"
    else mark_fail "geoclue" "${LAST_ERR:-could not disable geoclue}"; fi
  else
    mark_skip "geoclue" "not enabled"
  fi
  case "$DE" in
    gnome|cinnamon)
      gset org.gnome.system.location enabled false
      gset org.gnome.desktop.privacy report-technical-problems false
      gset org.gnome.desktop.privacy send-software-usage-stats false ;;
  esac
}

apply_lid_behavior() {
  log "Power: laptop lid behavior"
  local conf=/etc/systemd/logind.conf
  [ -f "$conf" ] || { info "no logind.conf"; return 0; }
  if ! grep -q '^HandleLidSwitch=' "$conf"; then
    if printf 'HandleLidSwitch=suspend\nHandleLidSwitchExternalPower=suspend\n' >> "$conf" 2>/dev/null; then
      mark_set "lid -> suspend (restart systemd-logind to apply)"
    else
      mark_fail "lid behavior" "could not write $conf"
    fi
  else
    mark_skip "lid behavior" "already configured"
  fi
}

apply_resolution() {
  [ -z "${CFG_resolution:-}" ] && return 0
  case "$CFG_resolution" in *[0-9]x[0-9]*) ;; *) return 0 ;; esac
  log "Display resolution: ${CFG_resolution}"
  # Wayland sessions cannot be driven by xrandr.
  if [ -n "${WAYLAND_DISPLAY:-}" ] || [ "$(printf '%s' "${XDG_SESSION_TYPE:-}" | tr '[:upper:]' '[:lower:]')" = "wayland" ]; then
    mark_manual "display resolution" "Wayland session: set ${CFG_resolution} in Settings > Displays"; return 0
  fi
  if ! have_cmd xrandr; then
    local pkg=""
    case "$PM" in apt) pkg="x11-xserver-utils" ;; dnf|zypper) pkg="xorg-x11-server-utils" ;; pacman) pkg="xorg-xrandr" ;; esac
    ask_install_addition "display resolution" "$pkg" "set the screen resolution with xrandr" \
      || { mark_manual "display resolution" "set ${CFG_resolution} in Settings > Displays"; return 0; }
  fi
  local xr out cur mode="$CFG_resolution"
  xr="$(run_as_user xrandr 2>/dev/null)"
  out="$(printf '%s\n' "$xr" | awk '/ connected/{print $1; exit}')"
  cur="$(printf '%s\n' "$xr" | awk '/\*/{print $1; exit}')"
  [ -z "$out" ] && { mark_manual "display resolution" "no connected display found via xrandr"; return 0; }
  [ "$cur" = "$mode" ] && { mark_skip "display resolution" "already $mode"; return 0; }
  if capture run_as_user xrandr --output "$out" --mode "$mode"; then mark_set "resolution $out = $mode"
  else mark_fail "display resolution" "${LAST_ERR:-xrandr could not set $mode on $out (mode may be unsupported)}"; fi
}

apply_mouse() {
  [ -z "${CFG_mouse_size:-}${CFG_mouse_speed:-}${CFG_mouse_accel:-}${CFG_mouse_swap:-}${CFG_mouse_dblclick:-}" ] && return 0
  log "Mouse: pointer size / speed / acceleration / buttons"
  case "$DE" in
    gnome|cinnamon)
      [ -n "${CFG_mouse_size:-}" ]  && gset org.gnome.desktop.interface cursor-size "$CFG_mouse_size"
      [ -n "${CFG_mouse_speed:-}" ] && gset org.gnome.desktop.peripherals.mouse speed "$CFG_mouse_speed"
      [ -n "${CFG_mouse_accel:-}" ] && gset org.gnome.desktop.peripherals.mouse accel-profile "'$CFG_mouse_accel'"
      [ -n "${CFG_mouse_swap:-}" ]  && gset org.gnome.desktop.peripherals.mouse left-handed "$CFG_mouse_swap"
      [ -n "${CFG_mouse_dblclick:-}" ] && gset org.gnome.desktop.peripherals.mouse double-click "$CFG_mouse_dblclick" ;;
    *) mark_manual "mouse settings" "set pointer size/speed in your DE settings" ;;
  esac
}

apply_appearance() {
  [ -z "${CFG_color_scheme:-}${CFG_accent:-}${CFG_night_light:-}" ] && return 0
  log "Appearance: theme / accent / night light"
  case "$DE" in
    gnome|cinnamon)
      [ -n "${CFG_color_scheme:-}" ] && gset org.gnome.desktop.interface color-scheme "'$CFG_color_scheme'"
      # GTK theme dark variant follows the color-scheme on most modern desktops.
      [ "${CFG_color_scheme:-}" = "prefer-dark" ] && gset org.gnome.desktop.interface gtk-theme "'Adwaita-dark'"
      [ -n "${CFG_accent:-}" ] && gset org.gnome.desktop.interface accent-color "'$CFG_accent'"
      [ -n "${CFG_night_light:-}" ] && gset org.gnome.settings-daemon.plugins.color night-light-enabled "$CFG_night_light" ;;
    *) mark_manual "appearance" "set theme/accent in your DE settings" ;;
  esac
}

apply_touchpad() {
  [ -z "${CFG_touchpad_tap:-}${CFG_touchpad_natural:-}" ] && return 0
  log "Touchpad: tap-to-click / natural scroll"
  case "$DE" in
    gnome|cinnamon)
      [ -n "${CFG_touchpad_tap:-}" ]     && gset org.gnome.desktop.peripherals.touchpad tap-to-click "$CFG_touchpad_tap"
      [ -n "${CFG_touchpad_natural:-}" ] && gset org.gnome.desktop.peripherals.touchpad natural-scroll "$CFG_touchpad_natural" ;;
    *) mark_manual "touchpad" "set tap-to-click / natural scroll in your DE settings" ;;
  esac
}

apply_power_timeouts() {
  [ -z "${CFG_sleep_ac:-}${CFG_sleep_dc:-}" ] && return 0
  log "Power: sleep timeouts"
  case "$DE" in
    gnome|cinnamon)
      [ -n "${CFG_sleep_ac:-}" ] && gset org.gnome.settings-daemon.plugins.power sleep-inactive-ac-timeout "$CFG_sleep_ac"
      [ -n "${CFG_sleep_dc:-}" ] && gset org.gnome.settings-daemon.plugins.power sleep-inactive-battery-timeout "$CFG_sleep_dc" ;;
    *) mark_manual "power timeouts" "set sleep timeouts in your DE settings" ;;
  esac
}

apply_locale() {
  [ -z "${CFG_locale:-}" ] && return 0
  log "Locale: ${CFG_locale}"
  have_cmd localectl || { mark_manual "locale" "set LANG=${CFG_locale} (no localectl)"; return 0; }
  local cur; cur="$(localectl status 2>/dev/null | sed -n 's/.*LANG=//p' | head -n1)"
  if [ "$cur" = "$CFG_locale" ]; then mark_skip "locale" "already $CFG_locale"
  elif capture localectl set-locale "LANG=$CFG_locale"; then mark_set "locale = $CFG_locale"
  else mark_fail "locale" "${LAST_ERR:-localectl set-locale failed (locale may need generating)}"; fi
}

apply_proxy() {
  case "${CFG_proxy_mode:-}" in
    '') return 0 ;;
    none) case "$DE" in gnome|cinnamon) gset org.gnome.system.proxy mode "'none'" ;; esac; return 0 ;;
  esac
  log "Proxy: ${CFG_proxy_mode}"
  case "$DE" in
    gnome|cinnamon)
      case "$CFG_proxy_mode" in
        manual)
          gset org.gnome.system.proxy mode "'manual'"
          if [ -n "${CFG_proxy_host:-}" ]; then
            gset org.gnome.system.proxy.http host "'$CFG_proxy_host'"
            gset org.gnome.system.proxy.https host "'$CFG_proxy_host'"
            [ -n "${CFG_proxy_port:-}" ] && { gset org.gnome.system.proxy.http port "$CFG_proxy_port"; gset org.gnome.system.proxy.https port "$CFG_proxy_port"; }
          fi ;;
        auto)
          gset org.gnome.system.proxy mode "'auto'"
          [ -n "${CFG_proxy_autoconfig:-}" ] && gset org.gnome.system.proxy autoconfig-url "'$CFG_proxy_autoconfig'" ;;
      esac ;;
    *) mark_manual "proxy" "set the proxy in your DE settings" ;;
  esac
  # Also export to /etc/environment for CLI tools (manual mode only).
  if [ "$CFG_proxy_mode" = "manual" ] && [ -n "${CFG_proxy_host:-}" ] && [ -n "${CFG_proxy_port:-}" ]; then
    local url="http://${CFG_proxy_host}:${CFG_proxy_port}"
    if [ -f /etc/environment ] && grep -qiE "^http_proxy=.*${CFG_proxy_host}:${CFG_proxy_port}" /etc/environment; then
      mark_skip "proxy env" "already in /etc/environment"
    else
      { printf 'http_proxy=%s\nhttps_proxy=%s\nHTTP_PROXY=%s\nHTTPS_PROXY=%s\n' "$url" "$url" "$url" "$url" >> /etc/environment; } 2>/dev/null \
        && mark_set "proxy env -> /etc/environment ($url)" || mark_fail "proxy env" "could not write /etc/environment"
    fi
  fi
}

apply_hosts() {
  [ -z "$(printf '%s' "$HOSTS_DATA" | tr -d '[:space:]')" ] && return 0
  log "Hosts file: custom entries -> /etc/hosts"
  local line added=0
  while IFS= read -r line; do
    [ -z "$line" ] && continue
    if grep -qF "$line" /etc/hosts 2>/dev/null; then mark_skip "hosts: $line" "already present"; continue; fi
    if printf '%s\n' "$line" >> /etc/hosts 2>/dev/null; then mark_set "hosts: $line"; added=$((added+1))
    else mark_fail "hosts: $line" "could not append to /etc/hosts"; fi
  done <<EOF
$(printf '%s\n' "$HOSTS_DATA")
EOF
  [ "$added" -gt 0 ] && info "added $added custom hosts entr(ies)"
}

apply_printers() {
  [ -z "$(printf '%s' "$PRINTERS_DATA" | tr -d '[:space:]')" ] && return 0
  log "Network printers -> CUPS"
  if ! have_cmd lpadmin; then
    ask_install_addition "network printers" "cups" "add the migrated network printers" || { mark_manual "printers" "install CUPS, then add the printers"; return 0; }
  fi
  local name host uri
  while IFS="$(printf '\t')" read -r name host; do
    [ -z "$name" ] && continue
    if lpstat -p "$name" >/dev/null 2>&1; then mark_skip "printer: $name" "already configured"; continue; fi
    case "$host" in http://*|https://*|ipp://*) uri="$host" ;; *) uri="ipp://${host}/ipp/print" ;; esac
    if capture lpadmin -p "$(printf '%s' "$name" | tr ' ' '_')" -E -v "$uri" -m everywhere; then
      mark_set "printer: $name -> $uri"
    else mark_manual "printer: $name" "add it manually (tried $uri)"; fi
  done <<EOF
$(printf '%s\n' "$PRINTERS_DATA")
EOF
}

apply_netcfg() {
  [ -z "$(printf '%s' "$NETCFG_DATA" | tr -d '[:space:]')" ] && return 0
  # Deploying the static network config is optional: it was staged on Windows,
  # but ask before emitting it here so the user can opt out.
  if [ -r /dev/tty ]; then
    warn "Static network configuration was exported from Windows. Do you want to apply it on this system now? (y/n)"
    local dans; printf '  (y/n): ' > /dev/tty; read -r dans < /dev/tty || dans="n"
    case "$dans" in [Yy]*) ;; *) mark_skip "network config" "deployment skipped by user"; return 0 ;; esac
  else
    mark_skip "network config" "deployment is optional; no terminal available to confirm"; return 0
  fi
  log "Static IP / DNS (manual - not auto-applied so networking can't break)"
  local iface ip gw dns
  while IFS="$(printf '\t')" read -r iface ip gw dns; do
    [ -z "$iface$ip$dns" ] && continue
    mark_manual "network: $iface" "set via NetworkManager if wanted: ip=${ip:-?} gateway=${gw:-?} dns=${dns:-?}  (e.g. nmcli con mod <name> ipv4.addresses ${ip} ipv4.gateway ${gw} ipv4.dns '${dns}' ipv4.method manual)"
  done <<EOF
$(printf '%s\n' "$NETCFG_DATA")
EOF
}

apply_accessibility() {
  [ -z "${CFG_a11y_stickykeys:-}${CFG_a11y_slowkeys:-}${CFG_a11y_bouncekeys:-}${CFG_a11y_mousekeys:-}${CFG_a11y_highcontrast:-}${CFG_a11y_magnifier:-}${CFG_a11y_screenreader:-}" ] && return 0
  log "Accessibility options"
  case "$DE" in
    gnome|cinnamon)
      [ -n "${CFG_a11y_stickykeys:-}" ]   && gset org.gnome.desktop.a11y.keyboard stickykeys-enable "$CFG_a11y_stickykeys"
      [ -n "${CFG_a11y_slowkeys:-}" ]     && gset org.gnome.desktop.a11y.keyboard slowkeys-enable "$CFG_a11y_slowkeys"
      [ -n "${CFG_a11y_bouncekeys:-}" ]   && gset org.gnome.desktop.a11y.keyboard bouncekeys-enable "$CFG_a11y_bouncekeys"
      [ -n "${CFG_a11y_mousekeys:-}" ]    && gset org.gnome.desktop.a11y.keyboard mousekeys-enable "$CFG_a11y_mousekeys"
      [ -n "${CFG_a11y_magnifier:-}" ]    && gset org.gnome.desktop.a11y.applications screen-magnifier-enabled "$CFG_a11y_magnifier"
      [ -n "${CFG_a11y_screenreader:-}" ] && gset org.gnome.desktop.a11y.applications screen-reader-enabled "$CFG_a11y_screenreader"
      [ -n "${CFG_a11y_highcontrast:-}" ] && gset org.gnome.desktop.a11y.interface high-contrast "$CFG_a11y_highcontrast" ;;
    *) mark_manual "accessibility" "set accessibility options in your DE settings" ;;
  esac
}

apply_timezone_timesync() {
  [ -z "${CFG_timezone:-}${CFG_ntp_server:-}" ] && return 0
  log "Timezone & time synchronization"
  if [ -n "${CFG_timezone:-}" ] && [ "$CFG_timezone" != "unknown" ] && have_cmd timedatectl; then
    local curtz; curtz="$(timedatectl show -p Timezone --value 2>/dev/null)"
    if [ "$curtz" = "$CFG_timezone" ]; then mark_skip "timezone" "already $CFG_timezone"
    elif capture timedatectl set-timezone "$CFG_timezone"; then mark_set "timezone = $CFG_timezone"
    else mark_fail "timezone" "${LAST_ERR:-timedatectl set-timezone failed for $CFG_timezone}"; fi
  fi
  # Time synchronization with a non-Microsoft NTP server.
  local ntp="${CFG_ntp_server:-}"
  case "$ntp" in *time.windows.com*|"") ntp="pool.ntp.org" ;; esac
  have_cmd timedatectl && { capture timedatectl set-ntp true >/dev/null 2>&1 || true; }
  local conf=/etc/systemd/timesyncd.conf
  if [ -f "$conf" ] || systemctl list-unit-files 2>/dev/null | grep -q '^systemd-timesyncd'; then
    if [ -f "$conf" ] && grep -qE "^NTP=${ntp}( |$)" "$conf"; then
      mark_skip "ntp server" "already $ntp"
    else
      if [ -f "$conf" ] && grep -qE '^[#[:space:]]*NTP=' "$conf"; then
        sed -i -E "s|^[#[:space:]]*NTP=.*|NTP=${ntp}|" "$conf" 2>/dev/null
      elif [ -f "$conf" ] && grep -qE '^\[Time\]' "$conf"; then
        sed -i -E "s|^\[Time\]|[Time]\nNTP=${ntp}|" "$conf" 2>/dev/null
      else
        printf '[Time]\nNTP=%s\n' "$ntp" >> "$conf" 2>/dev/null
      fi
      systemctl restart systemd-timesyncd 2>/dev/null || true
      mark_set "ntp server = $ntp (systemd-timesyncd)"
    fi
  elif have_cmd chronyd || have_cmd chronyc; then
    mark_manual "ntp server" "chrony present: add 'server $ntp iburst' to /etc/chrony.conf and restart chrony"
  else
    if ask_install_addition "time synchronization" "chrony" "synchronize the clock with $ntp"; then
      mark_manual "ntp server" "add 'server $ntp iburst' to /etc/chrony.conf and restart chrony"
    else
      mark_skip "ntp server" "no time-sync service available"
    fi
  fi
}

apply_wifi() {
  [ -z "$(printf '%s' "$WIFI_DATA" | tr -d '[:space:]')" ] && return 0
  log "WiFi known networks"
  if ! have_cmd nmcli; then
    mark_manual "wifi networks" "NetworkManager (nmcli) not present; import WiFi profiles manually"; return 0
  fi
  # If any entry carries an encrypted key, a transfer password WAS provided on
  # Windows: ask once to decrypt the keys.
  local has_enc=0 wifikey=""
  printf '%s\n' "$WIFI_DATA" | awk -F'\t' '$4=="enc"{f=1} END{exit !f}' && has_enc=1
  if [ "$has_enc" = "1" ]; then
    have_cmd openssl || ask_install_addition "wifi passwords" "openssl" "decrypt the exported WiFi passwords" || true
    # The decryption password was collected once, up front (ask_xfer_password); reuse it.
    have_cmd openssl && wifikey="$MIGRATE_XFER_PWD"
  else
    # No transfer password was provided on Windows (or it timed out): there may be
    # password-protected networks with no stored key. Ask whether to import them
    # anyway (manual password entry per network). "No" skips WiFi entirely.
    local has_prot=0
    printf '%s\n' "$WIFI_DATA" | awk -F'\t' '$1!="" && tolower($2)!="open" && tolower($2)!="none" && $4!="enc"{f=1} END{exit !f}' && has_prot=1
    if [ "$has_prot" = "1" ] && [ -r /dev/tty ]; then
      local YEL=$'\033[1;33m' RST=$'\033[0m' wans
      printf '\n  You %sdid not%s provide a %spassword%s for sensitive data encryption while exporting your data on Windows (or providing a %spassword%s was %stimed out%s).\n' "$YEL" "$RST" "$YEL" "$RST" "$YEL" "$RST" "$YEL" "$RST" >&3
      printf '  Do you still want to transfer WiFi networks without their passwords?\n' >&3
      printf '  (if "yes", manual password entry for each password-protected one is required)\n' >&3
      printf '  If you %sdid not%s intend for this, you can go over to Windows and export your data again with providing the encryption pass this time. (y/n)\n' "$YEL" "$RST" >&3
      printf '  (y/n): ' > /dev/tty; read -r wans < /dev/tty || wans="y"
      case "$wans" in [Nn]*) mark_skip "wifi networks" "skipped (no transfer password provided on Windows)"; return 0 ;; esac
    fi
  fi
  local ssid auth secret sectype psk exists
  while IFS="$(printf '\t')" read -r ssid auth secret sectype; do
    [ -z "$ssid" ] && continue
    # Does a connection profile of this name already exist? Networks WITH a password
    # update the existing profile's password (below); others are left as-is / skipped.
    exists=0
    if nmcli -t -g NAME connection show 2>/dev/null | grep -qxF "$ssid"; then exists=1; fi
    # Open networks have no key: add them straight away (no password needed).
    case "$(printf '%s' "$auth" | tr '[:upper:]' '[:lower:]')" in
      open|none|"")
        if [ "$exists" = "1" ]; then mark_skip "wifi: $ssid" "connection already exists"; continue; fi
        if capture nmcli connection add type wifi con-name "$ssid" ssid "$ssid" connection.autoconnect yes; then
          mark_set "wifi: $ssid (open network)"
        else mark_fail "wifi: $ssid" "${LAST_ERR:-nmcli could not add the connection}"; fi
        continue ;;
    esac
    psk=""
    case "$sectype" in
      enc) if [ -n "$wifikey" ] && have_cmd openssl; then
             psk="$(printf '%s' "$secret" | openssl enc -d -aes-256-cbc -pbkdf2 -salt -base64 -A -pass pass:"$wifikey" 2>/dev/null)" || psk=""
           fi ;;
      plain) psk="$secret" ;;
    esac
    if [ -n "$psk" ]; then
      if [ "$exists" = "1" ]; then
        # Already present: update its saved password rather than skipping.
        if capture nmcli connection modify "$ssid" wifi-sec.key-mgmt wpa-psk wifi-sec.psk "$psk"; then
          mark_set "wifi: $ssid (password updated)"
        else mark_fail "wifi: $ssid" "${LAST_ERR:-nmcli could not update the password}"; fi
      elif capture nmcli connection add type wifi con-name "$ssid" ssid "$ssid" \
           wifi-sec.key-mgmt wpa-psk wifi-sec.psk "$psk" connection.autoconnect yes; then
        mark_set "wifi: $ssid (with saved password)"
      else mark_fail "wifi: $ssid" "${LAST_ERR:-nmcli could not add the connection}"; fi
    else
      if [ "$exists" = "1" ]; then mark_skip "wifi: $ssid" "connection already exists"; continue; fi
      if capture nmcli connection add type wifi con-name "$ssid" ssid "$ssid" connection.autoconnect yes; then
        mark_manual "wifi: $ssid" "profile added WITHOUT password - enter the WiFi password to connect"
      else mark_fail "wifi: $ssid" "${LAST_ERR:-nmcli could not add the connection}"; fi
    fi
  done <<EOF
$(printf '%s\n' "$WIFI_DATA")
EOF
}

# --------------------------------------------------------------------------------------
# Windows -> Linux firewall mapping helpers.
#
# Windows exports each rule as:  name | direction | action | enabled | protocol |
# localPort | remotePort | program | service.  A few Windows port fields are service
# *keywords* rather than numbers; translate the well-known ones here -- this is the SINGLE
# place to add more.  Windows sometimes tags a keyword with a direction suffix (e.g.
# "IPHTTPSOut", "IPTLSIn"); the variants are listed explicitly so they resolve too.
# Anything still non-numeric afterwards is reported as un-migratable on screen.
fw_port_alias() {  # fw_port_alias VALUE -> numeric port/range, or VALUE unchanged
  case "$(printf '%s' "$1" | tr '[:upper:]' '[:lower:]')" in
    rpcepmap|rpc-epmap)                                  printf '135' ;;          # RPC Endpoint Mapper
    rpc)                                                 printf '49152-65535' ;;  # dynamic RPC range (Windows ephemeral range)
    iphttps|iphttpsin|iphttpsout|iptls|iptlsin|iptlsout) printf '443' ;;          # IP-HTTPS / IP-over-TLS tunnelling
    teredo|teredoin|teredoout)                           printf '3544' ;;         # Teredo IPv6 tunnelling
    mdns|mdnsin|mdnsout)                                 printf '5353' ;;         # multicast DNS
    ply2disc|playtodiscovery|playto)                     printf '3702' ;;         # Play-To device discovery (WS-Discovery)
    wsd|wsdevents|wsdeventssecure)                        printf '5357' ;;         # Web Services on Devices (WSDAPI)
    ssdp|ssdpin|ssdpout)                                 printf '1900' ;;         # SSDP / UPnP discovery
    dhcp)                                                printf '68' ;;           # DHCP client
    dns)                                                 printf '53' ;;           # DNS
    llmnr)                                               printf '5355' ;;         # Link-Local Multicast Name Resolution
    *)                                                   printf '%s' "$1" ;;
  esac
}

# --------------------------------------------------------------------------------------
# OpenSnitch (program-scoped firewalling) helpers.
#
# Windows firewall rules can be scoped to a specific program (.exe), which ufw/firewalld
# cannot express -- they only know ports/IPs. OpenSnitch is the Linux equivalent: it keys
# rules on the originating binary. When a migrated rule is program-scoped (typically the
# "any port" rules that are too broad to recreate as a port rule), we install OpenSnitch
# on first encounter and write an equivalent process-path rule instead of giving up.

# Return the bare exe name for a REAL application program path, or empty for "no program"
# and for Windows system pseudo-programs that have no Linux counterpart (svchost, System,
# core service hosts). Empty -> caller falls back to the manual-review message.
fw_program_exe() {  # fw_program_exe WINDOWS_PROGRAM_PATH -> exe basename or empty
  local p="$1" base
  case "$p" in ""|[Aa]ny|[Ss]ystem) return 0 ;; esac
  base="${p##*\\}"; base="${base##*/}"          # strip Windows (or Unix) directory
  case "$(printf '%s' "$base" | tr '[:upper:]' '[:lower:]')" in
    ""|svchost.exe|services.exe|lsass.exe|system|spoolsv.exe|taskhostw.exe) return 0 ;;
  esac
  printf '%s' "$base"
}

# Lazily install + enable OpenSnitch the first time a program-scoped rule needs it.
# Memoised in OPENSNITCH_READY: 1=ready, 2=unavailable (do not retry per rule).
OPENSNITCH_READY=0
ensure_opensnitch() {
  case "$OPENSNITCH_READY" in 1) return 0 ;; 2) return 1 ;; esac
  if have_cmd opensnitchd; then OPENSNITCH_READY=1; return 0; fi
  if is_dry_run; then info "[dry-run] would install OpenSnitch for program-scoped firewall rules"; OPENSNITCH_READY=2; return 1; fi
  local pkgs
  case "$FAMILY" in
    debian) pkgs="opensnitch python3-opensnitch-ui" ;;
    *)      pkgs="opensnitch opensnitch-ui" ;;
  esac
  info "Installing OpenSnitch to migrate program-scoped firewall rule(s): $pkgs"
  pm_refresh
  # shellcheck disable=SC2086
  if capture pm_install $pkgs && have_cmd opensnitchd; then
    capture systemctl enable --now opensnitchd >/dev/null 2>&1 || true
    OPENSNITCH_READY=1; return 0
  fi
  OPENSNITCH_READY=2; return 1
}

# Write one OpenSnitch rule that allows/blocks a program by its exe name, regardless of
# which Wine prefix / install path it ends up in (matched as a path regexp on the
# basename). Returns 1 if the rule file could not be written.
opensnitch_add_rule() {  # opensnitch_add_rule EXE ACTION RULE_NAME
  local exe="$1" act="$2" rname="$3" dir="/etc/opensnitchd/rules" slug osact re_exe re_json now
  is_dry_run && return 0
  mkdir -p "$dir" 2>/dev/null || return 1
  osact="allow"; [ "$act" = "Block" ] && osact="deny"
  slug="$(printf '%s' "$rname" | tr '[:upper:] ' '[:lower:]-' | tr -cd 'a-z0-9-' | cut -c1-60)"
  [ -n "$slug" ] || slug="rule"
  # Make the exe name a literal RE2 match by wrapping every character in its own class
  # ([a] matches "a"); this neutralises all regex metacharacters portably (no need to
  # enumerate them). Then JSON-escape backslashes. On Linux the process path always uses
  # '/', so we only anchor on the basename.
  re_exe="$(printf '%s' "$exe" | sed 's/[^^]/[&]/g; s/\^/\\^/g')"
  re_json="$(printf '%s' "$re_exe" | sed 's/\\/\\\\/g')"
  now="$(date -u '+%Y-%m-%dT%H:%M:%SZ' 2>/dev/null || date '+%Y-%m-%dT%H:%M:%S')"
  cat > "$dir/migrated-$slug.json" <<JSON || return 1
{
  "created": "$now",
  "updated": "$now",
  "name": "migrated-$slug",
  "enabled": true,
  "precedence": false,
  "nolog": false,
  "action": "$osact",
  "duration": "always",
  "operator": {
    "type": "regexp",
    "operand": "process.path",
    "sensitive": false,
    "data": "(?i).*/${re_json}\$",
    "list": []
  }
}
JSON
}

# Apply ONE concrete (port-or-range, transport) rule on the active backend ($backend).
# ufw wants ranges as N:M, firewalld as N-M.  Sets LAST_ERR on failure; returns 0 on
# success (or when an identical firewalld rule already exists), 1 on failure.
fw_apply_one() {  # fw_apply_one PORT_OR_RANGE PROTO ACTION DIR
  local e="$1" pp="$2" act="$3" d="$4"
  case "$backend" in
    ufw)
      local ue="$e"; case "$e" in *-*) ue="${e%-*}:${e#*-}" ;; esac
      local verb="allow"; [ "$act" = "Block" ] && verb="deny"
      local dirflag="in"; case "$d" in *out*) dirflag="out" ;; esac
      capture ufw "$verb" "$dirflag" "${ue}/${pp}" ;;
    firewalld)
      local fwaction="accept"; [ "$act" = "Block" ] && fwaction="reject"
      local rich="rule family=\"ipv4\" port port=\"${e}\" protocol=\"${pp}\" ${fwaction}"
      firewall-cmd --permanent --query-rich-rule="$rich" >/dev/null 2>&1 && return 0
      capture firewall-cmd --permanent --add-rich-rule="$rich" ;;
  esac
}

apply_firewall() {
  [ -z "$(printf '%s' "$FIREWALL_DATA" | tr -d '[:space:]')" ] && return 0
  # Deploying the exported firewall rules is optional: the rules were staged on
  # Windows, but ask before applying them here so the user can opt out.
  if [ -r /dev/tty ]; then
    warn "Firewall rules were exported from Windows. Do you want to apply them on this system now?"
    warn "If you skip, no rules are created (you can re-run later to apply them). (y/n)"
    local dans; printf '  (y/n): ' > /dev/tty; read -r dans < /dev/tty || dans="n"
    case "$dans" in [Yy]*) ;; *) mark_skip "firewall rules" "deployment skipped by user"; return 0 ;; esac
  else
    mark_skip "firewall rules" "deployment is optional; no terminal available to confirm"; return 0
  fi
  log "Firewall rules"
  local backend="" enablecmd=""
  if have_cmd ufw; then backend="ufw"; enablecmd="ufw enable"
  elif have_cmd firewall-cmd; then backend="firewalld"; enablecmd="systemctl enable --now firewalld"
  else
    local pkg=""; case "$FAMILY" in debian) pkg="ufw" ;; *) pkg="firewalld" ;; esac
    if ask_install_addition "firewall rules" "$pkg" "create the migrated firewall rules"; then
      if have_cmd ufw; then backend="ufw"; enablecmd="ufw enable"
      elif have_cmd firewall-cmd; then backend="firewalld"; enablecmd="systemctl enable --now firewalld"; fi
    fi
    [ -z "$backend" ] && { mark_manual "firewall rules" "no ufw/firewalld available"; return 0; }
  fi

  local name dir action enabled proto lport rport program service dirl port plow protos applied problem p e pp oldifs exe
  while IFS="$(printf '\t')" read -r name dir action enabled proto lport rport program service; do
    [ -z "$name" ] && continue
    proto="$(printf '%s' "$proto" | tr '[:upper:]' '[:lower:]')"
    dirl="$(printf '%s' "$dir" | tr '[:upper:]' '[:lower:]')"

    # Disabled-on-Windows rules are not migrated; record them in the log only.
    if [ "$enabled" != "True" ]; then record_line LOG "fw: $name" "disabled on Windows - not migrated"; continue; fi

    # Pick the port that actually matters for the direction: an INbound rule is about the
    # local listening port; an OUTbound rule is about the destination port it connects to
    # (its local port is just an ephemeral source). Fall back to the other if one is empty.
    case "$dirl" in
      *out*) port="$rport"; [ -z "$port" ] && port="$lport" ;;
      *)     port="$lport"; [ -z "$port" ] && port="$rport" ;;
    esac
    port="$(fw_port_alias "$port")"
    plow="$(printf '%s' "$port" | tr '[:upper:]' '[:lower:]')"

    # No concrete port -> a whole-protocol allow, too broad to recreate as a ufw/firewalld
    # port rule. If the Windows rule was scoped to a real program, recreate that scope with
    # OpenSnitch (installed on first use) instead of giving up. Otherwise (no program, or a
    # Windows system pseudo-program with no Linux counterpart) report it for manual review.
    case "$plow" in
      ""|any|"*")
        exe="$(fw_program_exe "$program")"
        if [ -n "$exe" ] && ensure_opensnitch; then
          if opensnitch_add_rule "$exe" "$action" "$name"; then
            mark_set "Windows program-scoped rule: Applied through OpenSnitch. $name (${action} ${dirl}, program '${exe}')"
          else
            mark_manual "fw: $name" "program-scoped ('${exe}'); could not write the OpenSnitch rule - add it manually in the OpenSnitch UI"
          fi
        elif [ -n "$exe" ]; then
          mark_manual "fw: $name" "program-scoped ('${exe}') but OpenSnitch is unavailable on this distro; install OpenSnitch and add the rule manually"
        else
          mark_manual "fw: $name" "Windows rule opens ANY port (proto='${proto:-Any}', dir='${dir}') with no specific program; a blanket allow is too broad to apply automatically - review manually"
        fi
        continue ;;
    esac

    # Which transport(s) to open. 'Any' protocol with a real port -> both TCP and UDP.
    # ICMP / GRE / other port-less protocols cannot be expressed as port rules; Linux uses
    # its own sensible defaults for those, so report instead of failing.
    case "$proto" in
      tcp|udp) protos="$proto" ;;
      any|"")  protos="tcp udp" ;;
      *)       mark_manual "fw: $name" "protocol '${proto}' is not port-based (e.g. ICMP/GRE); not applied - Linux keeps its defaults for this"; continue ;;
    esac

    # Apply each port element separately (a Windows value can be a list like "1900,2869"
    # or a range like "49152-65535"), across each transport. This avoids any backend
    # multi-port syntax quirk; fw_apply_one translates the range separator per backend.
    applied=0; problem=""; unportable=""; oldifs="$IFS"
    IFS=','
    for p in $port; do
      IFS="$oldifs"
      e="$(printf '%s' "$p" | tr -d '[:space:]')"; [ -z "$e" ] && continue
      # A still-non-numeric value here is a Windows-specific service keyword (e.g. a Cast/
      # WSD/RPC keyword fw_port_alias does not know) with no portable Linux port -- that is
      # a SKIP, not a failure. Only a real backend rejection below counts as a failure.
      case "$e" in *[!0-9-]*|-*|*-|*-*-*) unportable="Windows service-keyword port '$e' has no portable Linux equivalent"; break ;; esac
      for pp in $protos; do
        if fw_apply_one "$e" "$pp" "$action" "$dirl"; then applied=$((applied+1))
        else problem="${LAST_ERR:-$backend rejected ${e}/${pp}}"; break; fi
      done
      [ -n "$problem" ] && break
    done
    IFS="$oldifs"

    if [ -n "$problem" ]; then
      mark_fail "fw: $name" "$problem (port='${port}', proto='${proto}')"
    elif [ -n "$unportable" ] && [ "$applied" -eq 0 ]; then
      mark_skip "fw: $name" "$unportable"
    elif [ "$applied" -gt 0 ]; then
      mark_set "fw: $name (${action} ${dirl} ${port}/${proto})"
    else
      record_line LOG "fw: $name" "nothing to apply (port='${port}', proto='${proto}')"
    fi
  done <<EOF
$(printf '%s\n' "$FIREWALL_DATA")
EOF

  # Reload so the transferred rules take effect regardless of the prompt below.
  case "$backend" in
    ufw)       ufw reload >/dev/null 2>&1 || true ;;
    firewalld) firewall-cmd --reload >/dev/null 2>&1 || true ;;
  esac

  # Ask (in yellow) whether to enable + start the firewall now.
  if [ -r /dev/tty ]; then
    warn "Firewall rules transferred. Do you want to enable and start firewall now?"
    warn "If you feel it might brake something you can skip it now."
    warn "You can always do that by executing sudo $enablecmd (y/n)"
    local ans; printf '  (y/n): ' > /dev/tty; read -r ans < /dev/tty || ans="n"
    case "$ans" in
      [Yy]*) if capture sh -c "$enablecmd"; then mark_set "firewall enabled ($enablecmd)"
             else mark_fail "firewall enable" "${LAST_ERR:-$enablecmd failed}"; fi ;;
      *)     info "firewall left disabled; enable later with: sudo $enablecmd" ;;
    esac
  fi
}

# =============================================================================
#  POST-INSTALL phase  (runs AFTER apps are installed)
# =============================================================================
# Where C_detect staged the user's personal files. apply_settings.sh lives in
# submodules/, so its grandparent dir is "Execute on Linux!" -> migrated_user_data.
MIGRATE_STAGE="${MIGRATE_STAGE:-$(dirname "$(cd "$(dirname "$0")" && pwd)")/migrated_user_data}"

# Find an installed app's .desktop id by matching a Windows shortcut name / exe base.
# Echoes the .desktop basename (e.g. "org.videolan.VLC.desktop") or nothing.
resolve_desktop() {  # resolve_desktop "Display Name" "exebase"
  local disp="$1" exe="$2" d f base nlow
  local dirs="/usr/share/applications /var/lib/flatpak/exports/share/applications $TARGET_HOME/.local/share/applications"
  # 1) exe base name maps most reliably (e.g. "vlc" -> .../vlc.desktop).
  for d in $dirs; do
    [ -d "$d" ] || continue
    [ -n "$exe" ] || break
    for f in "$d/"*"${exe}"*.desktop; do
      [ -f "$f" ] && { basename "$f"; return 0; }
    done
  done
  # 2) fall back to a case-insensitive match on the desktop file's Name= field.
  nlow="$(printf '%s' "$disp" | tr '[:upper:]' '[:lower:]')"
  [ -n "$nlow" ] || return 1
  for d in $dirs; do
    [ -d "$d" ] || continue
    for f in "$d/"*.desktop; do
      [ -f "$f" ] || continue
      if grep -iqE "^Name=.*${nlow}" "$f" 2>/dev/null; then basename "$f"; return 0; fi
    done
  done
  return 1
}

# Append a .desktop id to the GNOME favourites list, idempotently.
add_favorite() {  # add_favorite "app.desktop"
  local id="$1" cur
  case "$DE" in gnome|cinnamon) ;; *) mark_manual "favourite: $id" "pin it in your DE manually"; return 0 ;; esac
  run_as_user gsettings list-keys org.gnome.shell 2>/dev/null | grep -qx favorite-apps || {
    mark_skip "favourite: $id" "org.gnome.shell favorite-apps not available on $DE"; return 0; }
  cur="$(run_as_user gsettings get org.gnome.shell favorite-apps 2>/dev/null)"   # e.g. ['a.desktop', 'b.desktop']
  case "$cur" in *"'$id'"*) mark_skip "favourite: $id" "already pinned"; return 0 ;; esac
  # An empty list is reported as "[]" OR (typed) "@as []"; strip the annotation + spaces.
  local newlist stripped
  stripped="$(printf '%s' "$cur" | sed 's/^@as //; s/[[:space:]]//g')"
  if [ -z "$cur" ] || [ "$stripped" = "[]" ]; then
    newlist="['$id']"
  else
    newlist="$(printf '%s' "$cur" | sed "s/]$/, '$id']/")"
  fi
  if capture run_as_user gsettings set org.gnome.shell favorite-apps "$newlist"; then mark_set "favourite pinned: $id"
  else mark_fail "favourite: $id" "${LAST_ERR:-could not update favorite-apps}"; fi
}

apply_shortcuts() {
  [ -z "$(printf '%s' "$SHORTCUTS_DATA" | tr -d '[:space:]')" ] && return 0
  log "Shortcuts (Quick Launch / Start menu / Desktop) -> installed apps"
  local appdir="$TARGET_HOME/.local/share/applications" kind disp exe did
  while IFS="$(printf '\t')" read -r kind disp exe; do
    [ -z "$disp$exe" ] && continue
    did="$(resolve_desktop "$disp" "$exe")" || { mark_skip "shortcut: ${disp:-$exe}" "no installed equivalent (skipped to avoid a broken link)"; continue; }
    case "$kind" in
      desktop)
        local src=""
        for d in /usr/share/applications /var/lib/flatpak/exports/share/applications "$appdir"; do
          [ -f "$d/$did" ] && { src="$d/$did"; break; }
        done
        [ -z "$src" ] && { mark_skip "desktop shortcut: $disp" "resolved app file not found"; continue; }
        mkdir -p "$TARGET_HOME/Desktop"
        if cp -f "$src" "$TARGET_HOME/Desktop/$did" 2>/dev/null; then
          chown "$TARGET_USER":"$TARGET_USER" "$TARGET_HOME/Desktop/$did" 2>/dev/null || true
          chmod +x "$TARGET_HOME/Desktop/$did" 2>/dev/null || true
          run_as_user gio set "$TARGET_HOME/Desktop/$did" metadata::trusted true >/dev/null 2>&1 || true
          mark_set "desktop shortcut: $disp -> $did"
        else mark_fail "desktop shortcut: $disp" "could not write to ~/Desktop"; fi ;;
      quicklaunch|startmenu) add_favorite "$did" ;;
      *) mark_skip "shortcut: $disp" "unknown kind '$kind'" ;;
    esac
  done <<EOF
$(printf '%s\n' "$SHORTCUTS_DATA")
EOF
}

# Record a note ONLY in the results log file -- not on screen, not in the printed
# summary (print_* ignores the NOTE status). Used for startup items / services with
# no Linux equivalent: harmless misses the user said "do not and cannot matter".
log_note() { record_line NOTE "$1" "${2:-}"; }

# Startup items -> XDG autostart, but ONLY when they resolve to an installed app.
# Scope is preserved: Windows machine-wide -> /etc/xdg/autostart (system); current
# user -> ~/.config/autostart (user). Non-resolving items are recorded log-only.
apply_startup_items() {
  [ -z "$(printf '%s' "$STARTUP_DATA" | tr -d '[:space:]')" ] && return 0
  log "Startup items -> autostart (resolved apps only)"
  local scope name exe did src d dest
  while IFS="$(printf '\t')" read -r scope name exe; do
    [ -z "$name$exe" ] && continue
    did="$(resolve_desktop "$name" "$exe")" || { log_note "startup: ${name:-$exe}" "no installed equivalent (left out; harmless)"; continue; }
    src=""
    for d in /usr/share/applications /var/lib/flatpak/exports/share/applications "$TARGET_HOME/.local/share/applications"; do
      [ -f "$d/$did" ] && { src="$d/$did"; break; }
    done
    [ -z "$src" ] && { log_note "startup: $name" "resolved app file not found"; continue; }
    case "$scope" in
      system) dest="/etc/xdg/autostart/$did" ;;
      *)      dest="$TARGET_HOME/.config/autostart/$did" ;;
    esac
    [ -e "$dest" ] && { mark_skip "startup: $name" "already in autostart"; continue; }
    mkdir -p "$(dirname "$dest")"
    if cp -f "$src" "$dest" 2>/dev/null; then
      [ "$scope" = "system" ] || chown "$TARGET_USER":"$TARGET_USER" "$dest" 2>/dev/null || true
      mark_set "startup ($scope): $name -> autostart"
    else mark_fail "startup: $name" "could not write autostart entry"; fi
  done <<EOF
$(printf '%s\n' "$STARTUP_DATA")
EOF
}

# Auto-start Windows services -> enable the systemd unit ONLY when a unit whose base
# name clearly matches exists (services are system scope). No match -> log-only note.
enable_services() {
  [ -z "$(printf '%s' "$SERVICES_DATA" | tr -d '[:space:]')" ] && return 0
  log "Auto-start services -> systemd (clear name matches only)"
  if ! have_cmd systemctl; then log_note "services" "systemctl not available"; return 0; fi
  local units disp name key unit
  units="$(systemctl list-unit-files --type=service --no-legend --no-pager 2>/dev/null | awk '{print $1}')"
  while IFS="$(printf '\t')" read -r disp name; do
    [ -z "$disp$name" ] && continue
    # Normalize the Windows service name to a bare alpha token (drop arch/version/punct).
    key="$(printf '%s' "$name" | tr '[:upper:]' '[:lower:]' | sed -E 's/x64|x86|amd64//g; s/[0-9]+//g; s/[^a-z]//g')"
    [ -z "$key" ] && { log_note "service: ${disp:-$name}" "no comparable name"; continue; }
    unit="$(printf '%s\n' "$units" | grep -iE "^${key}\.service$" | head -n1)"
    [ -z "$unit" ] && { log_note "service: ${disp:-$name}" "no clearly-matching systemd unit"; continue; }
    if systemctl is-enabled "$unit" >/dev/null 2>&1; then mark_skip "service: $disp" "$unit already enabled"; continue; fi
    if capture systemctl enable --now "$unit"; then mark_set "service: $disp -> enabled $unit"
    else mark_fail "service: $disp" "${LAST_ERR:-could not enable $unit}"; fi
  done <<EOF
$(printf '%s\n' "$SERVICES_DATA")
EOF
}

# Windows DaysOfWeek bitmask (Sun=1,Mon=2,...,Sat=64) -> cron day-of-week list (Sun=0..Sat=6).
win_mask_to_cron_dow() {  # win_mask_to_cron_dow MASK
  local m="$1" out="" dow
  case "$m" in ''|*[!0-9]*) printf '*'; return 0 ;; esac
  for dow in 0 1 2 3 4 5 6; do
    [ $(( m & (1 << dow) )) -ne 0 ] && out="${out:+$out,}$dow"
  done
  printf '%s' "${out:-*}"
}

# Manually-created Windows scheduled tasks -> cron, ONLY when the task's program
# resolves to an installed Linux app/binary. Scope: user task -> the user's crontab;
# system task -> root's crontab. Non-resolving / non-portable tasks are log-only.
apply_scheduled_tasks() {
  [ -z "$(printf '%s' "$SCHEDTASKS_DATA" | tr -d '[:space:]')" ] && return 0
  log "Scheduled tasks -> cron (resolved programs only)"
  if ! have_cmd crontab; then log_note "scheduled tasks" "crontab not available"; return 0; fi
  local name scope sched exe cmd cronexpr who did dir marker cur hh mm mask hm rest
  while IFS="$(printf '\t')" read -r name scope sched exe; do
    [ -z "$name$exe" ] && continue
    # Resolve a runnable command: a binary on PATH, else the resolved app's Exec.
    cmd=""
    if [ -n "$exe" ] && have_cmd "$exe"; then cmd="$exe"
    elif did="$(resolve_desktop "$name" "$exe")"; then
      for dir in /usr/share/applications /var/lib/flatpak/exports/share/applications "$TARGET_HOME/.local/share/applications"; do
        [ -f "$dir/$did" ] && { cmd="$(grep -m1 '^Exec=' "$dir/$did" 2>/dev/null | sed 's/^Exec=//; s/ *%[a-zA-Z].*//')"; break; }
      done
    fi
    [ -z "$cmd" ] && { log_note "scheduled task: $name" "no installed program to run (skipped)"; continue; }
    # Build the cron schedule (10# forces base-10 so 08/09 don't read as bad octal).
    case "$sched" in
      daily,*)
        hm="${sched#daily,}"; hh="${hm%%,*}"; mm="${hm##*,}"
        cronexpr="$((10#${mm:-0})) $((10#${hh:-0})) * * *" ;;
      weekly,*)
        rest="${sched#weekly,}"; mask="${rest%%,*}"; hm="${rest#*,}"; hh="${hm%%,*}"; mm="${hm##*,}"
        cronexpr="$((10#${mm:-0})) $((10#${hh:-0})) * * $(win_mask_to_cron_dow "$mask")" ;;
      onstart|onlogon) cronexpr="@reboot" ;;
      *) log_note "scheduled task: $name" "trigger '$sched' not portable to cron (skipped)"; continue ;;
    esac
    case "$scope" in system) who="root" ;; *) who="$TARGET_USER" ;; esac
    marker="# migrated-task: $name"
    cur="$(crontab -u "$who" -l 2>/dev/null)"
    if printf '%s\n' "$cur" | grep -qF "$marker"; then mark_skip "scheduled task: $name" "already in $who crontab"; continue; fi
    if printf '%s\n%s\n%s %s\n' "$cur" "$marker" "$cronexpr" "$cmd" | crontab -u "$who" - 2>/dev/null; then
      mark_set "scheduled task ($scope): $name -> cron [$cronexpr] $cmd"
    else mark_fail "scheduled task: $name" "could not update $who crontab"; fi
  done <<EOF
$(printf '%s\n' "$SCHEDTASKS_DATA")
EOF
}

# C_detect packs the user's personal files into ONE encrypted archive next to the
# staging dir: "<migrated_user_data>.tar.enc" (AES-256-CBC / PBKDF2, same transfer
# password as WiFi). Decrypt + extract it ONCE into a private temp dir; copy_ssh and
# copy_contacts then read from there. STAGE_DIR is the dir they read; STAGE_TMP is
# cleaned up afterwards. If no archive but a plaintext staging dir exists (standalone
# / legacy), use that directly.
STAGE_DIR=""; STAGE_TMP=""
unpack_stage() {
  local archive="${MIGRATE_STAGE}.tar.enc"
  if [ ! -f "$archive" ]; then
    [ -d "$MIGRATE_STAGE" ] && [ -n "$(ls -A "$MIGRATE_STAGE" 2>/dev/null)" ] && STAGE_DIR="$MIGRATE_STAGE"
    return 0
  fi
  if ! have_cmd openssl; then ask_install_addition "personal data" "openssl" "decrypt your transferred SSH keys / Contacts / wallpaper" || { mark_skip "personal data" "openssl unavailable to decrypt the archive"; return 0; }; fi
  if ! have_cmd tar; then mark_skip "personal data" "tar unavailable to extract the archive"; return 0; fi
  # The decryption password was collected once, up front (ask_xfer_password); reuse it.
  local key="$MIGRATE_XFER_PWD"
  [ -z "$key" ] && { mark_skip "personal data" "no decryption password given (personal data skipped)"; return 0; }
  STAGE_TMP="$(mktemp -d 2>/dev/null || echo /tmp/mtl_stage.$$)"; mkdir -p "$STAGE_TMP"
  if openssl enc -d -aes-256-cbc -pbkdf2 -salt -pass pass:"$key" -in "$archive" 2>/dev/null | tar -xf - -C "$STAGE_TMP" 2>/dev/null; then
    STAGE_DIR="$STAGE_TMP"
  else
    rm -rf "$STAGE_TMP" 2>/dev/null || true; STAGE_TMP=""
    mark_fail "personal data" "could not decrypt the archive (wrong password?) - SSH/Contacts skipped"
  fi
}

cleanup_stage() {
  [ -n "$STAGE_TMP" ] && rm -rf "$STAGE_TMP" 2>/dev/null || true
}

copy_ssh() {
  local src="$STAGE_DIR/ssh"
  [ -n "$STAGE_DIR" ] && [ -d "$src" ] && [ -n "$(ls -A "$src" 2>/dev/null)" ] || return 0
  log "SSH keys / config -> ~/.ssh"
  local dest="$TARGET_HOME/.ssh" f base out
  mkdir -p "$dest"; chmod 700 "$dest" 2>/dev/null || true
  for f in "$src"/*; do
    [ -f "$f" ] || continue
    base="$(basename "$f")"
    out="$dest/$base"
    [ -e "$out" ] && { mark_skip "ssh: $base" "already exists (left untouched)"; continue; }
    if cp -f "$f" "$out" 2>/dev/null; then
      chown "$TARGET_USER":"$TARGET_USER" "$out" 2>/dev/null || true
      case "$base" in *.pub|config|known_hosts|authorized_keys) chmod 644 "$out" 2>/dev/null || true ;; *) chmod 600 "$out" 2>/dev/null || true ;; esac
      mark_set "ssh file: $base"
    else mark_fail "ssh: $base" "could not copy into ~/.ssh"; fi
  done
  chown "$TARGET_USER":"$TARGET_USER" "$dest" 2>/dev/null || true
}

copy_contacts() {
  local src="$STAGE_DIR/contacts"
  [ -n "$STAGE_DIR" ] && [ -d "$src" ] && [ -n "$(ls -A "$src" 2>/dev/null)" ] || return 0
  log "Contacts -> ~/Contacts"
  local dest="$TARGET_HOME/Contacts"
  mkdir -p "$dest"
  if cp -rn "$src"/. "$dest"/ 2>/dev/null; then
    chown -R "$TARGET_USER":"$TARGET_USER" "$dest" 2>/dev/null || true
    mark_set "contacts copied to ~/Contacts (.contact files are XML - import into your address book)"
  else
    mark_fail "contacts" "could not copy into ~/Contacts"
  fi
}

# Fonts are NOT migrated in the staged archive (they would bloat it by hundreds of MB).
# Instead, manual-install style: tell the user where to get fonts and ask for a directory
# (local path, or a mounted SMB/NFS share) of unzipped font files; search it <=3 levels
# deep and install every valid font found. Loops so several directories can be added.
install_fonts() {
  log "Custom fonts"
  is_dry_run && { mark_plan "fonts" "would prompt for a font directory to install from"; return 0; }
  if [ ! -r /dev/tty ]; then mark_skip "fonts" "no terminal to ask for a font directory"; return 0; fi
  local dest="$TARGET_HOME/.local/share/fonts" dir ans f n total=0
  info "Fonts are not auto-transferred. To bring your Windows fonts over:"
  info "  1) On Windows, copy the font files you want from %LOCALAPPDATA%\\Microsoft\\Windows\\Fonts"
  info "     and/or %SYSTEMROOT%\\Fonts  (i.e. C:\\Windows\\Fonts)  -- unzip them if they are zipped."
  info "  2) Put them in a directory reachable from THIS machine: a local folder, or a mounted"
  info "     SMB/NFS share (e.g. /mnt/share, /media/...)."
  info "  3) Enter that directory path below; it is searched recursively (up to 3 levels deep)"
  info "     and every .ttf/.otf/.ttc font found is installed into ~/.local/share/fonts."
  mkdir -p "$dest"
  while :; do
    printf "  Font directory ('path' to install / d=done when finished / s=skip to skip fonts): " > /dev/tty
    read -r ans < /dev/tty || ans="skip"
    case "$ans" in
      [Ss]|[Ss][Kk][Ii][Pp]) [ "$total" -eq 0 ] && mark_skip "fonts" "user skipped"; break ;;
      [Dd]|[Dd][Oo][Nn][Ee]) break ;;
      *)
        dir="$(resolve_user_path "$ans")"
        if [ -z "$dir" ] || [ ! -d "$dir" ]; then
          printf "\033[1;31m  Not a readable directory: '%s' -- enter a valid path, 'done', or 'skip'.\033[0m\n" "${dir:-$ans}" > /dev/tty; continue
        fi
        n=0
        while IFS= read -r f; do
          [ -f "$f" ] || continue
          cp -fn "$f" "$dest/" 2>/dev/null && n=$((n+1))
        done <<EOF
$(find "$dir" -maxdepth 3 -type f \( -iname '*.ttf' -o -iname '*.otf' -o -iname '*.ttc' -o -iname '*.otc' -o -iname '*.pfb' -o -iname '*.pcf' \) 2>/dev/null)
EOF
        if [ "$n" -gt 0 ]; then total=$((total+n)); info "installed $n font(s) from $dir"
        else printf "\033[1;33m  No font files found under '%s' (searched 3 levels deep).\033[0m\n" "$dir" > /dev/tty; fi
        ;;
    esac
  done
  if [ "$total" -gt 0 ]; then
    chown -R "$TARGET_USER":"$TARGET_USER" "$dest" 2>/dev/null || true
    have_cmd fc-cache && run_as_user fc-cache -f >/dev/null 2>&1 || true
    mark_set "fonts: installed $total font file(s) into ~/.local/share/fonts"
  fi
}

apply_wallpaper() {
  local src="$STAGE_DIR/wallpaper"
  [ -n "$STAGE_DIR" ] && [ -d "$src" ] && [ -n "$(ls -A "$src" 2>/dev/null)" ] || return 0
  log "Wallpaper -> desktop background"
  local img="" dest f
  for f in "$src"/*; do [ -f "$f" ] && { img="$f"; break; }; done
  [ -z "$img" ] && return 0
  dest="$TARGET_HOME/.local/share/backgrounds/$(basename "$img")"
  mkdir -p "$(dirname "$dest")"
  if cp -f "$img" "$dest" 2>/dev/null; then
    chown -R "$TARGET_USER":"$TARGET_USER" "$TARGET_HOME/.local/share/backgrounds" 2>/dev/null || true
    case "$DE" in
      gnome|cinnamon)
        gset org.gnome.desktop.background picture-uri "'file://$dest'"
        gset org.gnome.desktop.background picture-uri-dark "'file://$dest'" ;;
      *) mark_manual "wallpaper" "set $dest as your wallpaper" ;;
    esac
  else mark_fail "wallpaper" "could not copy the image"; fi
}

apply_default_browser() {
  [ -z "${CFG_default_browser:-}" ] && return 0
  log "Default web browser: ${CFG_default_browser}"
  have_cmd xdg-settings || { mark_manual "default browser" "set ${CFG_default_browser} as default in Settings"; return 0; }
  # Candidate .desktop ids per browser token, first installed one wins.
  local cands="" did=""
  case "$CFG_default_browser" in
    chrome)  cands="google-chrome.desktop google-chrome-stable.desktop com.google.Chrome.desktop" ;;
    firefox) cands="firefox.desktop firefox-esr.desktop org.mozilla.firefox.desktop" ;;
    edge)    cands="microsoft-edge.desktop com.microsoft.Edge.desktop" ;;
    brave)   cands="brave-browser.desktop com.brave.Browser.desktop" ;;
    opera)   cands="opera.desktop com.opera.Opera.desktop" ;;
  esac
  local c d
  for c in $cands; do
    for d in /usr/share/applications /var/lib/flatpak/exports/share/applications "$TARGET_HOME/.local/share/applications"; do
      [ -f "$d/$c" ] && { did="$c"; break 2; }
    done
  done
  [ -z "$did" ] && { mark_skip "default browser" "${CFG_default_browser} not installed"; return 0; }
  if capture run_as_user xdg-settings set default-web-browser "$did"; then mark_set "default browser = $did"
  else mark_fail "default browser" "${LAST_ERR:-xdg-settings failed}"; fi
}

run_pre() {
  apply_display_scaling
  apply_resolution
  apply_mouse
  apply_appearance
  apply_touchpad
  apply_power_timeouts
  apply_lock_timeout
  apply_keyboard_layout
  apply_accessibility
  apply_locale
  apply_proxy
  disable_telemetry_location
  apply_timezone_timesync
  apply_wifi
  apply_firewall
  apply_hosts
  apply_printers
  apply_netcfg
  apply_lid_behavior
  info "Note: keyboard shortcuts (copy/paste/screenshot/etc.) map to your DE's"
  info "      defaults on Linux; review System Settings > Keyboard if needed."
}

run_post() {
  apply_shortcuts
  apply_startup_items
  enable_services
  apply_scheduled_tasks
  unpack_stage
  copy_ssh
  copy_contacts
  apply_wallpaper
  cleanup_stage
  install_fonts
  apply_default_browser
}

main() {
  require_root
  detect_distro
  detect_arch
  detect_de
  MODULE="Config settings"
  # Phase: pre (before apps), post (after apps), or all (standalone). Default all.
  local phase="${1:-all}"
  log "Migrate to Linux  --  Apply Settings (${phase})"
  info "Distribution : ${DISTRO_NAME}"
  info "Desktop env  : ${DE}"

  # Decryption password for sensitive exported data (WiFi/SSH/Contacts/wallpaper) shares
  # one answer; ask once up front. In an orchestrated run execute_all already asked and
  # exported it, so this is a no-op there.
  ask_xfer_password

  case "$phase" in
    pre)  run_pre ;;
    post) run_post ;;
    *)    run_pre; run_post ;;
  esac

  print_summary
}

main "$@"
